diagram.d2:
direction: right
repo: { label: "repo"; class: actor }
scan: { label: "scanInventory\nimports · exports · routers" }
config: { label: "atlas-config\nfirstGuess / reconcile + drift"; class: store }
gather: { label: "buildAtlasDraft\nbuildDomainDraft"; class: changed }
human: { label: "human enrichment\npurpose · detail · why"; class: external }
assemble: { label: "assembleAtlas\nassembleDomain" }
lint: { label: "lint-atlas\ncompleteness floor" }
out: { label: "atlas.html + domain-<slug>/ pages" }
repo -> scan
scan -> config: modules
config -> gather: domains + edges
gather -> human: draft-when-absent
human -> assemble: enriched blocks
assemble -> out
lint -> assemble: gates (onWarn)

diagram.mermaid:
graph LR
  repo([repo]) --> scan["scanInventory\nimports · exports · routers"]
  scan -->|modules| config["atlas-config\nfirstGuess / reconcile + drift"]
  config -->|domains + edges| gather["buildAtlasDraft\nbuildDomainDraft"]
  gather -->|draft-when-absent| human["human enrichment\npurpose · detail · why"]
  human -->|enriched blocks| assemble["assembleAtlas\nassembleDomain"]
  assemble --> out["atlas.html + domain-slug pages"]
  lint["lint-atlas\ncompleteness floor"] -->|gates| assemble
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  classDef external fill:#f1f3f5,stroke:#adb5bd,color:#1b1b1b;
  classDef store fill:#e5dbff,stroke:#9775fa,color:#1b1b1b;
  class gather changed;
  class repo actor;
  class human external;
  class config store;
